import numpy as np
from scipy.stats import norm
from scipy.optimize import brentq, newton

def bs_price(S, K, T, r, sigma, option_type):
    """Helper: Black-Scholes price."""
    if T <= 0:
        if option_type == 'call':
            return max(S - K, 0)
        else:
            return max(K - S, 0)

    d1 = (np.log(S / K) + (r + sigma**2 / 2) * T) / (sigma * np.sqrt(T))
    d2 = d1 - sigma * np.sqrt(T)

    if option_type == 'call':
        return S * norm.cdf(d1) - K * np.exp(-r * T) * norm.cdf(d2)
    else:
        return K * np.exp(-r * T) * norm.cdf(-d2) - S * norm.cdf(-d1)

def vega(S, K, T, r, sigma):
    """Calculate vega for Newton's method."""
    d1 = (np.log(S / K) + (r + sigma**2 / 2) * T) / (sigma * np.sqrt(T))
    return S * norm.pdf(d1) * np.sqrt(T)

def implied_volatility(market_price, S, K, T, r, option_type='call', method='brent'):
    """
    Calculate implied volatility from market price.

    Args:
        market_price: Observed option price
        S, K, T, r: Black-Scholes parameters
        option_type: 'call' or 'put'
        method: 'brent' or 'newton'

    Returns:
        Implied volatility (or None if no solution)
    """
    # Check for valid price bounds
    if option_type == 'call':
        intrinsic = max(S - K * np.exp(-r * T), 0)
        upper_bound = S
    else:
        intrinsic = max(K * np.exp(-r * T) - S, 0)
        upper_bound = K * np.exp(-r * T)

    if market_price < intrinsic or market_price > upper_bound:
        return None

    def objective(sigma):
        return bs_price(S, K, T, r, sigma, option_type) - market_price

    try:
        if method == 'brent':
            iv = brentq(objective, 0.001, 5.0)
        else:  # newton
            def objective_newton(sigma):
                return bs_price(S, K, T, r, sigma, option_type) - market_price

            def derivative(sigma):
                return vega(S, K, T, r, sigma)

            iv = newton(objective_newton, x0=0.2, fprime=derivative, maxiter=100)

        return iv if iv > 0 else None
    except (ValueError, RuntimeError):
        return None

# Test
test_data = [
    {'market_price': 10.45, 'S': 100, 'K': 100, 'T': 1.0, 'r': 0.05, 'type': 'call'},
    {'market_price': 5.00, 'S': 100, 'K': 105, 'T': 0.5, 'r': 0.05, 'type': 'call'},
    {'market_price': 8.00, 'S': 100, 'K': 95, 'T': 0.25, 'r': 0.05, 'type': 'put'},
]

print("Implied Volatility Calculations:")
for data in test_data:
    iv = implied_volatility(data['market_price'], data['S'], data['K'], 
                            data['T'], data['r'], data['type'])
    print(f"\n  Market Price: ${data['market_price']:.2f} ({data['type']})")
    print(f"  Implied Vol: {iv:.1%}" if iv else "  No solution")

    # Verify
    if iv:
        verify_price = bs_price(data['S'], data['K'], data['T'], data['r'], iv, data['type'])
        print(f"  Verify Price: ${verify_price:.2f}")
